import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"跨源知識地圖","description":"","frontmatter":{},"headers":[],"relativePath":"resources/research/knowledge-map.md","filePath":"resources/research/knowledge-map.md","lastUpdated":1779796674000}'),o={name:"resources/research/knowledge-map.md"};function s(d,t,i,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="跨源知識地圖" tabindex="-1">跨源知識地圖 <a class="header-anchor" href="#跨源知識地圖" aria-label="Permalink to &quot;跨源知識地圖&quot;">​</a></h1><p>系統評估 16 個主題的研究覆蓋度、5 大跨來源共識、關鍵分歧點與未解問題。</p><blockquote><p>建立時間：2026-05-01 | 最後更新：2026-05-23</p></blockquote><hr><h2 id="_16-個主題的覆蓋度評估" tabindex="-1">16 個主題的覆蓋度評估 <a class="header-anchor" href="#_16-個主題的覆蓋度評估" aria-label="Permalink to &quot;16 個主題的覆蓋度評估&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主題</th><th>覆蓋度</th><th>主要來源</th></tr></thead><tbody><tr><td>Orchestration Loop 設計</td><td>★★★★★</td><td>Lilian Weng、Daily Dose DS、AHE 論文</td></tr><tr><td>Tool/Function Calling</td><td>★★★★★</td><td>Masood、Trivedy、工具重寫論文</td></tr><tr><td>Context Management</td><td>★★★★★</td><td>Chroma Context Rot、AHE、Thariq</td></tr><tr><td>Harness vs Model 分離</td><td>★★★★☆</td><td>Building Agents 論文、Inside Scaffold</td></tr><tr><td>Memory 系統設計</td><td>★★★★☆</td><td>Memory Survey 2603.07670、A-Mem、MemGPT</td></tr><tr><td>Verification/Evals</td><td>★★★★☆</td><td>Anthropic demystify-evals、LangChain</td></tr><tr><td>Prompt Caching</td><td>★★★★☆</td><td>Thariq、官方文件</td></tr><tr><td>Sub-agent 架構</td><td>★★★☆☆</td><td>Anthropic Engineering、Inside Scaffold</td></tr><tr><td>Security &amp; Guardrails</td><td>★★★☆☆</td><td>2506.08837、Anthropic secure deployment</td></tr><tr><td>CLAUDE.md/Rules 設計</td><td>★★★☆☆</td><td>HumanLayer、Karpathy、FRAMEWORK.md</td></tr><tr><td>Benchmark 評估</td><td>★★★☆☆</td><td>Terminal-Bench、SWE-bench</td></tr><tr><td>Harness 自動演化</td><td>★★★☆☆</td><td>AHE、Meta-Harness</td></tr><tr><td>Formal Methods</td><td>★★☆☆☆</td><td>Categorical Architecture 2605.12239</td></tr><tr><td>Cross-model 可移植性</td><td>★★☆☆☆</td><td>NLAH 論文</td></tr><tr><td>Enterprise Governance</td><td>★★☆☆☆</td><td>Anthropic April 23 Postmortem</td></tr><tr><td>Harness ROI 量化</td><td>★☆☆☆☆</td><td>分散在多篇，無統一框架</td></tr></tbody></table><hr><h2 id="_5-大跨來源共識" tabindex="-1">5 大跨來源共識 <a class="header-anchor" href="#_5-大跨來源共識" aria-label="Permalink to &quot;5 大跨來源共識&quot;">​</a></h2><h3 id="共識-1-harness-影響超過模型大小" tabindex="-1">共識 1：Harness 影響超過模型大小 <a class="header-anchor" href="#共識-1-harness-影響超過模型大小" aria-label="Permalink to &quot;共識 1：Harness 影響超過模型大小&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Vesper 論文（2605.15221）：算法發現任務上，harness 結構變異佔 <strong>40% 性能差距</strong>；模型大小只佔 <strong>30%</strong></li><li>Adapting Interface, Not Model（2605.22166）：<strong>95% 的模型適應效果</strong>可在 harness 層實現，成本 2%</li></ul><p><strong>各來源共識</strong>:</p><ul><li>Terminal-Bench 2.0：同模型，不同 harness 的 13pp 差距</li><li>LangChain：只改 harness（system prompt、tools、middleware、tracing、self-verification），讓 coding agent 從 Top 30 進到 Top 5</li><li>Masood：企業 AI 失敗 65% 源自 harness 層缺陷，而非模型限制</li></ul><p><strong>實踐結論</strong>: Harness 是一級制約因子，不是模型的工具。結構最佳化報酬率 &gt; 等待模型升級。</p><hr><h3 id="共識-2-context-管理是決定性瓶頸" tabindex="-1">共識 2：Context 管理是決定性瓶頸 <a class="header-anchor" href="#共識-2-context-管理是決定性瓶頸" aria-label="Permalink to &quot;共識 2：Context 管理是決定性瓶頸&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Chroma Context Rot 研究：<strong>18 個模型全部</strong>隨 context 增長效能下降（NIAH benchmark）</li><li>AHE 論文：12% 更少 token 達最佳成績</li><li>Ewan Mak 實地案例（Claude Sonnet 4.6）：<strong>58% → 81%</strong>（23pp），改動主要在 context 架構</li></ul><p><strong>實踐結論</strong>: Sub-agent context firewall、prompt caching、compaction 策略不是優化項，是必要架構。</p><hr><h3 id="共識-3-verification-loops-使品質提升-2-3×" tabindex="-1">共識 3：Verification Loops 使品質提升 2-3× <a class="header-anchor" href="#共識-3-verification-loops-使品質提升-2-3×" aria-label="Permalink to &quot;共識 3：Verification Loops 使品質提升 2-3×&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Daily Dose DS：Verification 能使品質提升 <strong>2-3 倍</strong></li><li>Anthropic Rajasekaran：Playwright UI 自動測試在 live environment 跑 integration tests</li><li>Anthropic best practices：「給 Claude 驗證機制」是最高槓桿單一動作</li></ul><p><strong>各來源共識</strong>:</p><ul><li>Weng：Self-Reflection 是 Planning 的核心組件</li><li>Eugene Yan：Evals pattern 是生產系統的基石</li><li>Anthropic demystify-evals：「評估 agent 時評的是 model + harness，兩者不可分」</li></ul><p><strong>實踐結論</strong>: 沒有驗證迴路的 harness 不是 harness，只是 scaffolding。</p><hr><h3 id="共識-4-ratchet-原則-—-每個失敗變成永久防護" tabindex="-1">共識 4：Ratchet 原則 — 每個失敗變成永久防護 <a class="header-anchor" href="#共識-4-ratchet-原則-—-每個失敗變成永久防護" aria-label="Permalink to &quot;共識 4：Ratchet 原則 — 每個失敗變成永久防護&quot;">​</a></h3><p><strong>來源</strong>:</p><ul><li>Mitchell Hashimoto（原話）：「Anytime you find an agent makes a mistake, you take the time to engineer a solution such that the agent never makes that mistake again.」</li><li>Addy Osmani：「Every line in a good AGENTS.md should be traceable back to a specific thing that went wrong.」</li><li>HumanLayer：CLAUDE.md + hooks 的 Ratchet 實踐</li></ul><p><strong>實踐結論</strong>: Harness 不是預先設計的，而是從失敗中沉澱出來的。</p><hr><h3 id="共識-5-工具設計是-schema-語言工程" tabindex="-1">共識 5：工具設計是 Schema 語言工程 <a class="header-anchor" href="#共識-5-工具設計是-schema-語言工程" aria-label="Permalink to &quot;共識 5：工具設計是 Schema 語言工程&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Trivedy 論文（2602.20426）：工具描述的<strong>措辭顯著影響</strong> agent 成功率；提出自動化重寫工具 schema 和描述以提升可靠性</li></ul><p><strong>各來源共識</strong>:</p><ul><li>Weng：工具是超越訓練數據的能力擴展管道</li><li>Masood：Tool/Function Calling 是 5 層 Control Plane 的第 2 層</li></ul><p><strong>實踐結論</strong>: 工具設計不只是功能問題，也是 schema 語言和描述精確度的工程問題。</p><hr><h2 id="分歧觀點" tabindex="-1">分歧觀點 <a class="header-anchor" href="#分歧觀點" aria-label="Permalink to &quot;分歧觀點&quot;">​</a></h2><h3 id="分歧-1-mcp-的投資報酬率" tabindex="-1">分歧 1：MCP 的投資報酬率 <a class="header-anchor" href="#分歧-1-mcp-的投資報酬率" aria-label="Permalink to &quot;分歧 1：MCP 的投資報酬率&quot;">​</a></h3><table tabindex="0"><thead><tr><th>立場</th><th>來源</th><th>論點</th></tr></thead><tbody><tr><td>保守</td><td>Simon Willison</td><td>不建議依賴 MCP；直接用 shell 命令更簡單和安全</td></tr><tr><td>積極</td><td>HumanLayer、Masood</td><td>MCP 是能力擴展主要途徑，採用 A2A 協議標準化</td></tr><tr><td>務實</td><td>FRAMEWORK.md</td><td>Bash + Read/Write + Glob 已覆蓋 90% 需求；MCP 有價值但不緊急</td></tr></tbody></table><p><strong>核心差異</strong>: Willison 優先安全隔離（Docker/Codespaces）；Masood 優先 context 效率與標準化。</p><hr><h3 id="分歧-2-model-進步後-harness-的演變方向" tabindex="-1">分歧 2：Model 進步後 Harness 的演變方向 <a class="header-anchor" href="#分歧-2-model-進步後-harness-的演變方向" aria-label="Permalink to &quot;分歧 2：Model 進步後 Harness 的演變方向&quot;">​</a></h3><table tabindex="0"><thead><tr><th>觀點</th><th>來源</th><th>預測</th></tr></thead><tbody><tr><td>Convergence（模型內化 harness 功能）</td><td>Trivedy</td><td>某些 harness 功能會成為模型原生能力</td></tr><tr><td>Substitution（簡單 harness 退場）</td><td>Anthropic Rajasekaran</td><td>V1 需要 sprint contracts，Opus 4.6 後不需要了</td></tr><tr><td>Permanence（校準型 harness 永遠留著）</td><td>RESEARCH.md</td><td>Harness 解的是 non-determinism，不是 model 弱點</td></tr></tbody></table><p><strong>深層分析</strong>:</p><ul><li>補弱點的 harness（early-stop、subagent for isolation）→ 隨模型進步消失</li><li>校準 non-determinism 的 harness（hooks、verification、planner-evaluator）→ 永遠留著</li></ul><hr><h3 id="分歧-3-verification-的自動化程度" tabindex="-1">分歧 3：Verification 的自動化程度 <a class="header-anchor" href="#分歧-3-verification-的自動化程度" aria-label="Permalink to &quot;分歧 3：Verification 的自動化程度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>立場</th><th>來源</th><th>方法</th></tr></thead><tbody><tr><td>深度自動化</td><td>Anthropic Rajasekaran</td><td>Playwright UI 自動測試，live interaction before scoring</td></tr><tr><td>模型內評估</td><td>Anthropic Young</td><td>Unit tests + browser automation</td></tr><tr><td>輕量快速</td><td>HumanLayer</td><td>Typecheck + lint + unit tests，只顯示 errors</td></tr><tr><td>多層驗證</td><td>Daily Dose DS</td><td>規則型/視覺型/LLM-as-judge 三種層次</td></tr></tbody></table><hr><h3 id="分歧-4-harness-厚度-thick-vs-thin" tabindex="-1">分歧 4：Harness 厚度（Thick vs Thin） <a class="header-anchor" href="#分歧-4-harness-厚度-thick-vs-thin" aria-label="Permalink to &quot;分歧 4：Harness 厚度（Thick vs Thin）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>立場</th><th>來源</th><th>立場</th></tr></thead><tbody><tr><td>Thick（重型 harness）</td><td>Daily Dose DS、Masood</td><td>11 組件完整架構；Control Plane 5 層</td></tr><tr><td>Thin + 迭代（漸進式）</td><td>Building Agents 論文</td><td>從最簡 harness 開始，失敗後 Ratchet 增厚</td></tr><tr><td>隨模型簡化</td><td>Daily Dose DS</td><td>好的 harness 是臨時基礎設施，隨模型進步應下降</td></tr></tbody></table><hr><h2 id="知識缺口-2026-05-評估" tabindex="-1">知識缺口（2026-05 評估） <a class="header-anchor" href="#知識缺口-2026-05-評估" aria-label="Permalink to &quot;知識缺口（2026-05 評估）&quot;">​</a></h2><h3 id="缺口-p0-harness-量化評估框架" tabindex="-1">缺口 P0：Harness 量化評估框架 <a class="header-anchor" href="#缺口-p0-harness-量化評估框架" aria-label="Permalink to &quot;缺口 P0：Harness 量化評估框架&quot;">​</a></h3><p><strong>現狀</strong>: Terminal-Bench 提供模型級基準，但無法診斷「特定 harness 的健康度」。</p><p><strong>建議</strong>:</p><ul><li>量化「context firewall 效率」（sub-agent 的中間輸出 vs 最終結論 token 比）</li><li>量化「Ratchet 累積度」（規則數量與覆蓋的失敗模式）</li></ul><h3 id="缺口-p0-rule-escalation-決策樹" tabindex="-1">缺口 P0：Rule Escalation 決策樹 <a class="header-anchor" href="#缺口-p0-rule-escalation-決策樹" aria-label="Permalink to &quot;缺口 P0：Rule Escalation 決策樹&quot;">​</a></h3><p><strong>現狀</strong>: 「每個失敗要變成規則」的哲學清楚，但「何時升格為 hook vs 留在 CLAUDE.md」無明確指引。</p><p><strong>建議</strong>: 建立決策樹：人工遵守率 × 違反成本 → 決定是否升格為 code 層 hook。</p><h3 id="缺口-p0-基準評測污染危機-2026-05-23-新增" tabindex="-1">缺口 P0：基準評測污染危機（2026-05-23 新增） <a class="header-anchor" href="#缺口-p0-基準評測污染危機-2026-05-23-新增" aria-label="Permalink to &quot;缺口 P0：基準評測污染危機（2026-05-23 新增）&quot;">​</a></h3><p><strong>現狀</strong>:</p><ul><li>DebugML「Cheating Agents」論文：業界排名前 20 的 agent 系統中 <strong>67% 顯示基準污染信號</strong></li><li>污染類型：訓練集洩露、基準過擬合、評測集污染、結果後選擇性報告</li></ul><p><strong>影響</strong>: Terminal-Bench 等成績可能虛高 15-30 pp；部分跨來源比較數據可信度下降。</p><h3 id="缺口-p1-sub-agent-委派的精確閾值驗證" tabindex="-1">缺口 P1：Sub-Agent 委派的精確閾值驗證 <a class="header-anchor" href="#缺口-p1-sub-agent-委派的精確閾值驗證" aria-label="Permalink to &quot;缺口 P1：Sub-Agent 委派的精確閾值驗證&quot;">​</a></h3><p><strong>現狀</strong>: 「≥10 檔案」「&gt;20 工具呼叫」是啟發式規則，無量化驗證。Sub-agent 的「收支平衡點」（開銷 token vs 救回的 context rot token）尚未測量。</p><h3 id="缺口-p1-long-horizon-的自動化進度追蹤" tabindex="-1">缺口 P1：Long-Horizon 的自動化進度追蹤 <a class="header-anchor" href="#缺口-p1-long-horizon-的自動化進度追蹤" aria-label="Permalink to &quot;缺口 P1：Long-Horizon 的自動化進度追蹤&quot;">​</a></h3><p><strong>建議</strong>: 規範化 Progress 格式（JSON schema for <code>claude-progress.txt</code>）；自動偵測「premature completion」的 hook；Session 間自動驗證「新工作與舊工作無衝突」。</p><h3 id="缺口-p2-model-版本升級時-harness-的遷移指南" tabindex="-1">缺口 P2：Model 版本升級時 Harness 的遷移指南 <a class="header-anchor" href="#缺口-p2-model-版本升級時-harness-的遷移指南" aria-label="Permalink to &quot;缺口 P2：Model 版本升級時 Harness 的遷移指南&quot;">​</a></h3><p><strong>現狀</strong>: April 23 Postmortem 顯示 harness 改動造成整體性下滑，但無升級新模型時的 harness 微調指南。</p><hr><h2 id="_2026-05-新增主題" tabindex="-1">2026-05 新增主題 <a class="header-anchor" href="#_2026-05-新增主題" aria-label="Permalink to &quot;2026-05 新增主題&quot;">​</a></h2><h3 id="harness-作為範疇論架構-categorical-theory-foundation" tabindex="-1">Harness 作為範疇論架構（Categorical Theory Foundation） <a class="header-anchor" href="#harness-作為範疇論架構-categorical-theory-foundation" aria-label="Permalink to &quot;Harness 作為範疇論架構（Categorical Theory Foundation）&quot;">​</a></h3><p><strong>來源</strong>: Harness as Categorical Architecture（2605.12239）</p><p><strong>核心洞見</strong>:</p><ul><li>工具 = 物件（Objects）</li><li>管道 = 態射（Morphisms）</li><li>組合 = 函子律（Functorial Composition）</li><li>形式驗證：harness chain 的正確性可通過範疇圖進行證明</li></ul><h3 id="五層-runtime-substrate-分離關切" tabindex="-1">五層 Runtime Substrate 分離關切 <a class="header-anchor" href="#五層-runtime-substrate-分離關切" aria-label="Permalink to &quot;五層 Runtime Substrate 分離關切&quot;">​</a></h3><p><strong>來源</strong>: Runtime Substrate（2605.13357）</p><table tabindex="0"><thead><tr><th>層級</th><th>責任</th><th>範例</th></tr></thead><tbody><tr><td><strong>Invocation Layer</strong></td><td>Model ↔ Tool 介面</td><td>Function call parsing、retry logic</td></tr><tr><td><strong>Context Layer</strong></td><td>上下文可見性管理</td><td>Compaction、windowing、injection</td></tr><tr><td><strong>Memory Layer</strong></td><td>短期/長期狀態</td><td>Session cache、vector DB、prompt cache</td></tr><tr><td><strong>Coordination Layer</strong></td><td>工具編排與順序</td><td>Pipeline routing、parallel execution</td></tr><tr><td><strong>Reflection Layer</strong></td><td>自我監視與調適</td><td>Error detection、performance metrics、rule learning</td></tr></tbody></table><p><strong>實踐結論</strong>: 清晰分層減少耦合，提高可測試性；各層獨立優化不破壞他層。</p><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="/cc-workspace-docs/resources/research/harness-engineering/">Harness Engineering 研究全景</a></li><li><a href="/cc-workspace-docs/resources/reference/">延伸閱讀與參考資料</a></li><li><a href="/cc-workspace-docs/lectures/lecture-04-harness-architecture/">Lecture 04：Harness 三層架構</a></li></ul>',86)])])}const p=e(o,[["render",s]]);export{u as __pageData,p as default};
